#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    qsort(arr, n, sizeof(int), compare);
    int min_diff = arr[1] - arr[0];
    for (int i = 1; i < n - 1; i++) {
        if (arr[i + 1] - arr[i] < min_diff) {
            min_diff = arr[i + 1] - arr[i];
        }
    }
    printf("%d\n", min_diff);
    return 0;
}

